files.flake.nix:
{
  description = "mofaflex - Factor Analysis Models";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        pyPkgs = pkgs.python311Packages;
        coreScope = { inherit (pkgs) lib; };
        callPackageWith = pkgs.lib.callPackageWith;
        customPackages = rec {
          mudata = callPackageWith (pyPkgs // customPackages // coreScope) ./mudata {};
          main = callPackageWith (pyPkgs // customPackages // coreScope) ./main {};
          mofaflex = main;
        };
      in {
        packages = customPackages // {
          default = customPackages.main;
        };
      }
    );
}

files.main/default.nix:
{
  lib,
  buildPythonPackage,
  fetchPypi,
  hatchling,
  setuptools,
  wheel,
  setuptools-scm,
  anndata,
  array-api-compat,
  dtw-python,
  gpytorch,
  h5py,
  mizani,
  mudata,
  numpy,
  packaging,
  pandas,
  platformdirs,
  plotnine,
  pyro-ppl,
  scikit-learn,
  scipy,
  session-info2,
  statsmodels,
  torch,
  tqdm,
}:

buildPythonPackage rec {
  pname = "mofaflex";
  version = "0.1.0.post1";
  pyproject = true;

  src = fetchPypi {
    inherit pname version;
    hash = lib.fakeHash;
  };

  build-system = [
    hatchling
    setuptools
    wheel
    setuptools-scm
  ];

  dependencies = [
    anndata
    array-api-compat
    dtw-python
    gpytorch
    h5py
    mizani
    mudata
    numpy
    packaging
    pandas
    platformdirs
    plotnine
    pyro-ppl
    scikit-learn
    scipy
    session-info2
    statsmodels
    torch
    tqdm
  ];

  pythonImportsCheck = [ "mofaflex" ];

  doCheck = false;

  meta = {
    description = "Factor Analysis Models";
    homepage = "https://github.com/bioFAM/mofaflex";
    license = lib.licenses.bsd3;
    maintainers = with lib.maintainers; [ ];
  };
}

